use serde::{Deserialize, Serialize};
use std::fs;
use thiserror::Error;

#[derive(Debug, Deserialize, Serialize)]
struct Config {
    host: String,
    port: u16,
    database: DatabaseConfig,
}

#[derive(Debug, Deserialize, Serialize)]
struct DatabaseConfig {
    url: String,
    max_connections: u32,
}

#[derive(Debug, Error)]
enum ConfigError {
    #[error("Failed to read file: {0}")]
    Io(#[from] std::io::Error),

    #[error("Failed to parse JSON: {0}")]
    Parse(#[from] serde_json::Error),

    #[error("Invalid port: must be between 1024 and 65535")]
    InvalidPort,
}

fn load_config(path: &str) -> Result<Config, ConfigError> {
    let contents = fs::read_to_string(path)?;
    let config: Config = serde_json::from_str(&contents)?;

    if config.port < 1024 {
        return Err(ConfigError::InvalidPort);
    }

    Ok(config)
}

fn main() {
    match load_config("config.json") {
        Ok(config) => println!("Loaded: {:?}", config),
        Err(ConfigError::Io(e)) => eprintln!("File error: {}", e),
        Err(ConfigError::Parse(e)) => eprintln!("JSON error: {}", e),
        Err(ConfigError::InvalidPort) => eprintln!("Invalid port in config"),
    }
}
