# cache.py
import json
import hashlib
from functools import wraps
from typing import Any, Optional
import redis

redis_client = redis.Redis(host='localhost', port=6379, decode_responses=True)

class CacheService:
    def __init__(self, client: redis.Redis, default_ttl: int = 300):
        self.client = client
        self.default_ttl = default_ttl

    def get(self, key: str) -> Optional[Any]:
        value = self.client.get(key)
        return json.loads(value) if value else None

    def set(self, key: str, value: Any, ttl: int = None) -> None:
        self.client.setex(key, ttl or self.default_ttl, json.dumps(value))

    def delete(self, key: str) -> None:
        self.client.delete(key)

    def invalidate_pattern(self, pattern: str) -> None:
        keys = self.client.keys(pattern)
        if keys:
            self.client.delete(*keys)

cache = CacheService(redis_client)

def cached(ttl: int = 300, key_prefix: str = ''):
    def decorator(func):
        @wraps(func)
        async def wrapper(*args, **kwargs):
            cache_key = f"{key_prefix}:{func.__name__}:{hashlib.md5(str(args+tuple(sorted(kwargs.items()))).encode()).hexdigest()}"

            cached_result = cache.get(cache_key)
            if cached_result is not None:
                return cached_result

            result = await func(*args, **kwargs)
            cache.set(cache_key, result, ttl)
            return result
        return wrapper
    return decorator

# Usage
@cached(ttl=60, key_prefix='users')
async def get_user(user_id: int):
    # DB query here
    return {'id': user_id, 'name': 'Ana'}
