public class BST<T extends Comparable<T>> {
    private Node root;

    private class Node {
        T data;
        Node left, right;
        Node(T data) { this.data = data; }
    }

    public void insert(T value) {
        root = insertRec(root, value);
    }

    private Node insertRec(Node node, T value) {
        if (node == null) return new Node(value);
        int cmp = value.compareTo(node.data);
        if (cmp < 0) node.left = insertRec(node.left, value);
        else if (cmp > 0) node.right = insertRec(node.right, value);
        return node;
    }

    public boolean contains(T value) {
        Node curr = root;
        while (curr != null) {
            int cmp = value.compareTo(curr.data);
            if (cmp == 0) return true;
            curr = cmp < 0 ? curr.left : curr.right;
        }
        return false;
    }

    public void inOrder(java.util.function.Consumer<T> action) {
        inOrderRec(root, action);
    }

    private void inOrderRec(Node node, java.util.function.Consumer<T> action) {
        if (node == null) return;
        inOrderRec(node.left, action);
        action.accept(node.data);
        inOrderRec(node.right, action);
    }

    public T min() {
        if (root == null) throw new java.util.NoSuchElementException();
        Node curr = root;
        while (curr.left != null) curr = curr.left;
        return curr.data;
    }
}
