export function calculateDiscount(price, discountPercent, userTier) {
  if (price < 0) throw new Error('Price cannot be negative');
  if (discountPercent < 0 || discountPercent > 100) throw new Error('Invalid discount');

  const tierMultiplier = { gold: 1.5, silver: 1.2, basic: 1.0 };
  const multiplier = tierMultiplier[userTier] ?? 1.0;
  const finalDiscount = Math.min(discountPercent * multiplier, 100);

  return price * (1 - finalDiscount / 100);
}
