// utils.test.js — Vitest
import { describe, it, expect } from 'vitest';
import { calculateDiscount } from './utils';

describe('calculateDiscount', () => {
  it('applies basic discount correctly', () => {
    expect(calculateDiscount(100, 20, 'basic')).toBe(80);
  });

  it('applies gold tier multiplier (1.5x)', () => {
    // 20% * 1.5 = 30% discount
    expect(calculateDiscount(100, 20, 'gold')).toBe(70);
  });

  it('caps discount at 100%', () => {
    expect(calculateDiscount(100, 80, 'gold')).toBe(0); // 80*1.5=120, capped at 100
  });

  it('throws on negative price', () => {
    expect(() => calculateDiscount(-10, 20, 'basic')).toThrow('Price cannot be negative');
  });

  it('throws on invalid discount percentage', () => {
    expect(() => calculateDiscount(100, 110, 'basic')).toThrow('Invalid discount');
  });

  it('treats unknown tier as basic', () => {
    expect(calculateDiscount(100, 20, 'unknown')).toBe(80);
  });

  it('handles zero price', () => {
    expect(calculateDiscount(0, 50, 'gold')).toBe(0);
  });
});
